var minimumBoxes = function(n) {
    let total = 0, floor = 0, k = 0;
    while (total + ((k + 1) * (k + 2)) / 2 <= n) {
        k++;
        total += (k * (k + 1)) / 2;
        floor += k;
    }
    let j = 0;
    while (total < n) {
        j++;
        total += j;
        floor++;
    }
    return floor;
};
